const fs=require('fs');
const dir="C:/Users/MORONI~1/AppData/Local/Temp/claude/C--Users-moronisalvador-APPS/e9504981-700e-4f4d-8088-5b77bbc6d37a/scratchpad/";
const s=fs.readFileSync(dir+"pdf_streams.txt",'latin1');
let out=[];
let i=0,n=s.length;
while(i<n){
  let c=s[i];
  if(c==='('){
    // parse string literal
    let depth=1,j=i+1,buf='';
    while(j<n&&depth>0){
      let ch=s[j];
      if(ch==='\\'){
        let nx=s[j+1];
        if(nx>='0'&&nx<='7'){
          // octal up to 3 digits
          let oct=nx;j+=2;
          for(let k=0;k<2&&s[j]>='0'&&s[j]<='7';k++){oct+=s[j];j++;}
          buf+=String.fromCharCode(parseInt(oct,8));
          continue;
        } else {
          const map={'n':'\n','r':'\r','t':'\t','b':'\b','f':'\f','(':'(',')':')','\\':'\\'};
          buf+=(map[nx]!==undefined?map[nx]:nx);
          j+=2;continue;
        }
      } else if(ch==='('){depth++;buf+=ch;j++;}
      else if(ch===')'){depth--;if(depth>0)buf+=ch;j++;}
      else {buf+=ch;j++;}
    }
    out.push(buf);
    i=j;
  } else i++;
}
fs.writeFileSync(dir+"pdf_text.txt",out.join(""),'utf8');
console.log("strings:",out.length);

const fs=require('fs');
const dir="C:/Users/MORONI~1/AppData/Local/Temp/claude/C--Users-moronisalvador-APPS/e9504981-700e-4f4d-8088-5b77bbc6d37a/scratchpad/";
const s=fs.readFileSync(dir+"pdf_streams.txt",'latin1');
// Extract every parenthesized literal (simple, non-nested-safe) and join per BT/ET-ish.
// Just pull all (...) that look like text: printable, and concatenate with heuristics.
let res=[];
let i=0,n=s.length;
while(i<n){
  if(s[i]==='('){
    let j=i+1,buf='',depth=1;
    while(j<n&&depth>0&&j-i<2000){
      let ch=s[j];
      if(ch==='\\'){buf+=s[j+1];j+=2;continue;}
      if(ch==='('){depth++;buf+=ch;}
      else if(ch===')'){depth--;if(depth>0)buf+=ch;}
      else buf+=ch;
      j++;
    }
    // only keep if mostly printable ascii
    let printable=[...buf].filter(c=>c.charCodeAt(0)>=32&&c.charCodeAt(0)<127).length;
    if(buf.length>0&&printable/buf.length>0.8) res.push(buf);
    i=j;
  } else i++;
}
let text=res.join(" ");
fs.writeFileSync(dir+"clean.txt",text,'utf8');
console.log("segments:",res.length,"len:",text.length);
